import { Transaction, MatchResult, SearchFilters } from '../../types';
import { NameResolver } from '../../core/processors/NameResolver';
import { parseDate } from '../utils/parsingUtils';

/**
 * Lógica de filtragem UNIVERSAL e ROBUSTA.
 * Suporta busca por partes de data, valores flexíveis e texto.
 */
export const filterTransactionByUniversalQuery = (tx: Transaction, query: string): boolean => {
    if (!query || !query.trim() || !tx) return true;
    const terms = query.toLowerCase().trim().split(/\s+/).filter(t => t.length > 0);

    const rawDate = tx.date || '';
    const dateNormalized = rawDate.replace(/-/g, '/');
    const dateParts = dateNormalized.split('/');

    let dateBr = '';
    let dateShort = '';

    if (dateParts.length === 3) {
        if (dateParts[0].length === 4) {
            dateBr = `${dateParts[2]}/${dateParts[1]}/${dateParts[0]}`;
            dateShort = `${dateParts[2]}/${dateParts[1]}`;
        } else {
            dateBr = dateNormalized;
            dateShort = `${dateParts[0]}/${dateParts[1]}`;
        }
    }

    const displayDesc = (tx.cleanedDescription || tx.description || '').toLowerCase();
    const typeStr = (tx.contributionType || '').toLowerCase();

    const amount = Math.abs(tx.amount || 0);
    const amountStrFixed = amount.toFixed(2);
    const amountStrComma = amountStrFixed.replace('.', ',');

    return terms.every(term => {
        if (displayDesc.includes(term)) return true;
        if (typeStr.includes(term)) return true;
        if (amountStrFixed.includes(term)) return true;
        if (amountStrComma.includes(term)) return true;
        const dateTerm = term.replace(/[-.]/g, '/');
        if (dateBr.includes(dateTerm) || dateShort.includes(dateTerm)) return true;
        return false;
    });
};

/**
 * Lógica de filtragem para Resultados de Conciliação.
 */
export const filterByUniversalQuery = (result: MatchResult, query: string): boolean => {
    if (!query || !query.trim() || !result) return true;
    return filterTransactionByUniversalQuery(result.transaction, query);
};

/**
 * APLICA FILTROS AVANÇADOS (BLINDAGEM V3 - RESILIENTE)
 * Garante que qualquer combinação de filtros gere um relatório válido sem excluir dados por erro de lógica ou campos vazios.
 */
export const applyAdvancedFilters = (results: MatchResult[], filters: SearchFilters): MatchResult[] => {
    try {
        if (!Array.isArray(results)) return [];
        if (!filters) return results;

        let data = [...results];

        // 1. Normalização de Filtro de Tipo de Transação
        // Ignora se for 'all', vazio, nulo ou indefinido
        if (filters.transactionType && filters.transactionType !== 'all') {
            if (filters.transactionType === 'income') {
                data = data.filter(r => (r.status === 'PENDENTE' ? (r.contributorAmount || 0) : (r.transaction?.amount || 0)) >= 0);
            } else if (filters.transactionType === 'expenses') {
                data = data.filter(r => (r.status === 'PENDENTE' ? (r.contributorAmount || 0) : (r.transaction?.amount || 0)) < 0);
            }
        }

        // 2. Normalização de Filtro de Status da Conciliação
        // Ignora se for 'all', vazio ou nulo
        if (filters.reconciliationStatus && filters.reconciliationStatus !== 'all') {
            switch (filters.reconciliationStatus) {
                case 'confirmed_any':
                    data = data.filter(r => r.status === 'IDENTIFICADO');
                    break;
                case 'unconfirmed':
                    data = data.filter(r => r.status === 'NÃO IDENTIFICADO');
                    break;
                case 'confirmed_auto':
                    // Considera 'AUTOMATIC' ou 'LEARNED' ou nulo (default auto)
                    data = data.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod || r.matchMethod === 'TEMPLATE'));
                    break;
                case 'confirmed_manual':
                    // Considera 'MANUAL' ou 'AI' (sugestão aceita)
                    data = data.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
                    break;
            }
        }

        // 3. Normalização de Filtro por Categoria (Igreja ou Contribuinte)
        // Só aplica se o modo estiver selecionado E houver valor preenchido
        if (filters.filterBy === 'contributor' && filters.contributorName && filters.contributorName.trim().length > 0) {
            const query = filters.contributorName.toLowerCase().trim();
            data = data.filter(r => {
                const name = (r.contributor?.cleanedName || r.contributor?.name || r.transaction?.cleanedDescription || r.transaction?.description || '').toLowerCase();
                return name.includes(query);
            });
        }

        if (filters.filterBy === 'church' && Array.isArray(filters.churchIds) && filters.churchIds.length > 0) {
            data = data.filter(r => r.church?.id && filters.churchIds.includes(r.church.id));
        }

        // 4. Normalização de Filtro de Período (Data)
        // Só aplica se houver pelo menos uma data válida. Datas vazias ou nulas são ignoradas.
        if (filters.dateRange && (filters.dateRange.start || filters.dateRange.end)) {
            const startStr = filters.dateRange.start?.trim();
            const endStr = filters.dateRange.end?.trim();

            const startDate = startStr ? new Date(startStr).getTime() : null;
            const endDate = endStr ? new Date(endStr).getTime() + 86400000 : null; // Fim do dia

            if (startDate || endDate) {
                data = data.filter(r => {
                    const dateStr = r.status === 'PENDENTE' ? (r.contributor?.date || r.transaction?.date) : r.transaction?.date;
                    if (!dateStr) return false;
                    const itemDate = parseDate(dateStr)?.getTime();
                    if (!itemDate) return false;

                    if (startDate && itemDate < startDate) return false;
                    if (endDate && itemDate >= endDate) return false;
                    return true;
                });
            }
        }

        // 5. Normalização de Filtro de Valor
        // Só aplica se o operador for diferente de 'any' e houver pelo menos um valor preenchido.
        const vFilter = filters.valueFilter;
        if (vFilter && vFilter.operator !== 'any' && vFilter.value1 !== null && vFilter.value1 !== undefined) {
            data = data.filter(r => {
                const amount = Math.abs(r.status === 'PENDENTE' ? (r.contributorAmount || 0) : (r.transaction?.amount || 0));
                const val1 = vFilter.value1 || 0;
                const val2 = vFilter.value2 || 0;

                switch (vFilter.operator) {
                    case 'exact': return Math.abs(amount - val1) < 0.01;
                    case 'gt': return amount > val1;
                    case 'lt': return amount < val1;
                    case 'between': 
                        if (vFilter.value2 === null || vFilter.value2 === undefined) return amount >= val1;
                        return amount >= val1 && amount <= val2;
                    default: return true;
                }
            });
        }

        // Fallback absoluto: garante que nunca retorne undefined
        return data || [];
    } catch (error) {
        console.error("[applyAdvancedFilters] Erro fatal na filtragem:", error);
        // Em caso de erro catastrófico, retorna a lista original para não travar a UI
        return Array.isArray(results) ? results : [];
    }
};

import { useState, useMemo, useEffect, useContext, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { MatchResult } from '../types';
import { ExportService } from '../services/ExportService';
import { filterByUniversalQuery, applyAdvancedFilters } from '../services/processingService';

export type ReportCategory = 'general' | 'churches' | 'unidentified' | 'expenses';

export const useReportsController = () => {
    const { 
        reportPreviewData, 
        activeReportId, 
        saveCurrentReportChanges, 
        openSaveReportModal, 
        matchResults,
        updateReportData,
        runAiAutoIdentification,
        searchFilters
    } = useContext(AppContext);

    const { language } = useTranslation();
    const { setActiveView } = useUI();

    const [activeCategory, setActiveCategory] = useState<ReportCategory>('general');
    const [selectedReportId, setSelectedReportId] = useState<string | null>(null);
    const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' } | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        if (!reportPreviewData) return;

        if (activeCategory === 'general') {
            setSelectedReportId('general_all');
        } else if (activeCategory === 'churches') {
            const incomeData = reportPreviewData.income || {};
            const churchIds = Object.keys(incomeData).filter(k => k !== 'unidentified').sort();
            if (churchIds.length > 0) {
                if (!selectedReportId || !churchIds.includes(selectedReportId) || selectedReportId === 'general_all') {
                    setSelectedReportId(churchIds[0]);
                }
            } else {
                setSelectedReportId(null);
            }
        } else if (activeCategory === 'unidentified') {
            setSelectedReportId('unidentified');
        } else if (activeCategory === 'expenses') {
            setSelectedReportId('all_expenses_group');
        }
    }, [activeCategory, reportPreviewData]);

    const churchList = useMemo(() => {
        if (!reportPreviewData?.income) return [];
        return Object.entries(reportPreviewData.income)
            .filter(([id]) => id !== 'unidentified')
            .map(([id, results]) => {
                const res = Array.isArray(results) ? results : [];
                return {
                    id,
                    name: res[0]?.church?.name || 'Igreja Desconhecida',
                    count: res.length,
                    total: res.reduce((sum, r) => sum + (r.transaction?.amount || 0), 0)
                };
            })
            .sort((a, b) => a.name.localeCompare(b.name));
    }, [reportPreviewData]);

    const counts = useMemo(() => {
        const incomeGroups = reportPreviewData?.income || {};
        const general = Object.values(incomeGroups).flat().length;
        const churchesCount = churchList.length;
        const pending = incomeGroups['unidentified']?.length || 0;
        const expenses = reportPreviewData?.expenses?.['all_expenses_group']?.length || 0;
        return { general, churches: churchesCount, pending, expenses };
    }, [churchList, reportPreviewData]);

    const activeData = useMemo(() => {
        if (!reportPreviewData) return [];
        let data: MatchResult[] = [];

        try {
            // 1. Seleção da base por categoria
            if (activeCategory === 'general') {
                const incomeGroups = reportPreviewData.income || {};
                data = (Object.values(incomeGroups) as MatchResult[][]).flat();
            } else if (activeCategory === 'expenses') {
                data = reportPreviewData.expenses?.['all_expenses_group'] || [];
            } else if (selectedReportId) {
                data = reportPreviewData.income?.[selectedReportId] || [];
            }

            // 2. Aplicação de Filtros Avançados (Modal)
            // A função applyAdvancedFilters cuida da normalização internamente
            if (searchFilters) {
                data = applyAdvancedFilters(data, searchFilters);
            }

            // 3. Aplicação do Filtro de Busca Rápida (Texto)
            if (searchTerm && searchTerm.trim()) {
                data = data.filter(r => filterByUniversalQuery(r, searchTerm));
            }
        } catch (e) {
            console.error("[useReportsController] Erro ao processar activeData:", e);
        }

        // Fallback absoluto para garantir que nunca seja undefined
        return Array.isArray(data) ? data : [];
    }, [reportPreviewData, selectedReportId, activeCategory, searchTerm, searchFilters]);

    const sortedData = useMemo(() => {
        const source = Array.isArray(activeData) ? activeData : [];
        if (source.length === 0) return [];
        if (!sortConfig) return source;

        return [...source].sort((a, b) => {
            let valA: any, valB: any;
            const key = sortConfig.key;

            if (key === 'contributor.name' || key === 'transaction.description') {
                valA = a.contributor?.name || a.contributor?.cleanedName || a.transaction?.cleanedDescription || a.transaction?.description || '';
                valB = b.contributor?.name || b.contributor?.cleanedName || b.transaction?.cleanedDescription || b.transaction?.description || '';
            } else if (key.includes('.')) {
                const parts = key.split('.');
                valA = parts.reduce((obj: any, k) => obj?.[k], a);
                valB = parts.reduce((obj: any, k) => obj?.[k], b);
            } else {
                valA = (a as any)[key];
                valB = (b as any)[key];
            }

            valA = (valA ?? ''); 
            valB = (valB ?? '');

            if (typeof valA === 'string' && typeof valB === 'string') { 
                valA = valA.toLowerCase(); 
                valB = valB.toLowerCase(); 
            }

            if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
            if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [activeData, sortConfig]);

    const handleSort = (key: string) => {
        setSortConfig(prev => ({
            key,
            direction: prev?.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const activeSummary = useMemo(() => {
        if (!Array.isArray(activeData)) {
            return { count: 0, total: 0, auto: 0, autoValue: 0, manual: 0, manualValue: 0, pending: 0, pendingValue: 0 };
        }

        const total = activeData.reduce((sum, r) => sum + (r.status === 'PENDENTE' ? (r.contributorAmount || 0) : (r.transaction?.amount || 0)), 0);
        const autoTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod || r.matchMethod === 'TEMPLATE'));
        const manualTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
        const pendingTxs = activeData.filter(r => r.status === 'PENDENTE' || r.status === 'NÃO IDENTIFICADO');

        return { 
            count: activeData.length, total, 
            auto: autoTxs.length, autoValue: autoTxs.reduce((s, r) => s + (r.transaction?.amount || 0), 0),
            manual: manualTxs.length, manualValue: manualTxs.reduce((s, r) => s + (r.transaction?.amount || 0), 0),
            pending: pendingTxs.length, pendingValue: pendingTxs.reduce((s, r) => s + (r.status === 'PENDENTE' ? (r.contributorAmount || 0) : (r.transaction?.amount || 0)), 0)
        };
    }, [activeData]);

    const handleDownload = () => ExportService.downloadCsv(sortedData, `relatorio_${new Date().toISOString().slice(0,10)}.csv`);

    const handlePrint = () => {
        const title = activeCategory === 'general' ? 'Relatório Geral' : activeCategory === 'churches' ? (churchList.find(c => c.id === selectedReportId)?.name || 'Relatório') : activeCategory === 'unidentified' ? 'Pendentes' : 'Saídas';
        ExportService.printHtml(sortedData, title, activeSummary, language);
    };

    const handleSaveReport = () => openSaveReportModal({ type: 'global', results: matchResults, groupName: 'Geral' });

    return {
        activeCategory, setActiveCategory,
        selectedReportId, setSelectedReportId,
        searchTerm, setSearchTerm,
        sortConfig, setSortConfig,
        handleSort,
        churchList, counts, activeSummary, sortedData,
        activeReportId, saveCurrentReportChanges, runAiAutoIdentification,
        handleDownload, handlePrint, handleSaveReport, updateReportData,
        setActiveView, reportPreviewData,
        searchFilters
    };
};
